// n8n Code Node - Split Script into Sentences

// Get the input data
const inputData = $input.first();

// Function to split text into sentences
function splitIntoSentences(text) {
  // Sentence splitting - handles common abbreviations and patterns
  const sentences = text
    .replace(/([.!?])\s+/g, '$1|SPLIT|') // Mark sentence boundaries
    .replace(/([.!?])$/g, '$1|SPLIT|') // Handle end of text
    .split('|SPLIT|')
    .map(s => s.trim())
    .filter(s => s.length > 0); // Remove empty strings

  return sentences;
}

// Process the first item in the input
const scriptText = inputData.json['Script'];

if (!scriptText) {
  return [{
    json: {
      error: 'No "Scripts in German" field found'
    }
  }];
}

// Split the script into sentences
const sentences = splitIntoSentences(scriptText);

// Return array of items, each with a sentence object
return sentences.map((sentence, index) => ({
  json: {
    line: sentence,
    recordId: inputData.json['id'],
    lineNumber: index + 1,
  }
}));

