// n8n Code node – Mode: "Run Once for All Items" oder "for each", beides ok
const raw = String($input.first().json['Script German'] ?? '').trim();
let images = [];

let sentence = raw
  .replace(/\r?\n+/g, ' ')     // Zeilenumbrüche -> Leerzeichen
  .replace(/\s{2,}/g, ' ')     // doppelte Spaces
  .replace(/\s*,\s*/g, ', ')   // Kommas normieren
  .replace(/\s*\.\s*/g, '. ')  // Punkte normieren
  .replace(/\s*:\s*/g, ': ')   // Doppelpunkte
  .replace(/\s*;\s*/g, '; ')   // Semikolons
  .replace(/,\s*(,|\.|;)/g, '$1')
  .replace(/\s+([?!])/g, '$1')
  .replace(/\s+\)/g, ')')
  .replace(/\(\s+/g, '(')
  .replace(/\s+$/g, '')
  .replace(/([.?!]){2,}/g, '$1');

for (const image of $input.first().json['Visual Reference (Mandatory)']) {
  images.push(image.url);
}

const urls = images.join(', ')

return { json: { clean: sentence, urls: urls } };

return [{
  images: $input.first().json.images,
  video: $('Loop Over Items4').first().json.Video_Pipeline[0],
  line: $('Loop Over Items4').first().json.id,
  prompt: $('Image Prompt Generator').first().json.output,
}]

