// Get the input data
const inputData = $input.all();

// Process each item
return inputData.map(item => {
  // Get the output text
  let text = item.json.output;

  // Remove the prefix
  const prefixToRemove = "# OPTIMIZED SCRIPT WITH ELEVENLABS V3 TAGS:\n\n```\n";

  if (text.startsWith(prefixToRemove)) {
    text = text.slice(prefixToRemove.length);
  }

  // Return the cleaned text
  return {
    json: {
      ...item.json,
      output: text
    }
  };
});
